/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
///
/// If `count` is given, returns an array of the first `count` grapheme
/// clusters instead of a single string.
#[func]
pub fn first(
    &self,
    /// Number of characters to return as an array. If omitted, returns a
    /// single string.
    #[named]
    count: Option<usize>,
    /// A set of characters to strip from the start of the string before
    /// extracting.
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let s = match &strip {
        Some(strip) => self.0.trim_start_matches(|c| strip.contains(c)),
        None => self.0.as_str(),
    };

    match count {
        None => s
            .graphemes(true)
            .next()
            .map(|s| Str::from(s).into_value())
            .ok_or_else(string_is_empty),
        Some(count) => {
            let graphemes: Vec<_> = s.graphemes(true).take(count).collect();
            if graphemes.len() < count {
                return Err(count_exceeds_length());
            }
            Ok(Array::from_iter(graphemes.into_iter().map(Str::from))
                .into_value())
        }
    }
}

/// Extracts the last grapheme cluster of the string.
/// Fails with an error if the string is empty.
///
/// If `count` is given, returns an array of the last `count` grapheme
/// clusters instead of a single string.
#[func]
pub fn last(
    &self,
    /// Number of characters to return as an array. If omitted, returns a
    /// single string.
    #[named]
    count: Option<usize>,
    /// A set of characters to strip from the end of the string before
    /// extracting.
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let s = match &strip {
        Some(strip) => self.0.trim_end_matches(|c| strip.contains(c)),
        None => self.0.as_str(),
    };

    match count {
        None => s
            .graphemes(true)
            .next_back()
            .map(|s| Str::from(s).into_value())
            .ok_or_else(string_is_empty),
        Some(count) => {
            let mut graphemes: Vec<_> = s.graphemes(true).rev().take(count).collect();
            if graphemes.len() < count {
                return Err(count_exceeds_length());
            }
            graphemes.reverse();
            Ok(Array::from_iter(graphemes.into_iter().map(Str::from))
                .into_value())
        }
    }
}

